from microcoapy import CoAP, Resource

class TemperatureSensor(Resource):
    def __init__(self):
        super().__init__('/sensors/temp', ['GET', 'PUT'])
        self.value = 25.0  # Default temperature value

    def GET(self, request):
        return self.value

    def PUT(self, request):
        self.value = float(request.payload)
